// @spec SCORE-001
export function scorePair(x: Item, y: Item): number {
  const aOk = predicateA(x, y);
  const bOk = predicateB(x, y);
  if (aOk && bOk) return 3;
  if (aOk && !bOk) return 2;
  if (!aOk && bOk) return 1;
  return 0;
}

type Item = { id: string };
function predicateA(x: Item, y: Item): boolean { return x.id.length > y.id.length; }
function predicateB(x: Item, y: Item): boolean { return x.id < y.id; }

// @spec PREF-001
export function renderItems(items: Array<{ primary?: string; secondary?: string }>): string[] {
  const out: string[] = [];
  for (const item of items) {
    const text = item.primary || item.secondary || '';
    if (!text) continue;
    out.push(text);
  }
  return out;
}

// @spec DEDUP-001
export function uniqueIds(ids: readonly string[]): string[] {
  if (ids.length === 0) return [];
  const seen = new Set<string>();
  const out: string[] = [];
  for (const id of ids) {
    if (!seen.has(id)) {
      seen.add(id);
      out.push(id);
    }
  }
  return out;
}
